import React from 'react';
import { NavLink } from 'react-router-dom';
import logo from '../assets/logo.svg';

const Sidebar = () => {
  return (
    <div className="sidebar flex flex-col h-screen">
      <div className="flex items-center mb-8 p-4">
        <img src={logo} alt="NeuroFleetX Logo" className="w-12 h-12 mr-2" />
        <h2 className="g-brand">NeuroFleetX</h2>
      </div>
      <nav className="flex-1">
        <ul className="space-y-3 px-4">
          <li>
            <NavLink
              to="/"
              className={({ isActive }) =>
                `flex items-center space-x-2 p-2 rounded-md ${
                  isActive ? 'bg-blue-700 text-blue-300' : 'text-white hover:bg-gray-700'
                }`
              }
            >
              <span>🏠</span>
              <span>Dashboard</span>
            </NavLink>
          </li>
          <li>
            <NavLink
              to="/live-tracking"
              className={({ isActive }) =>
                `flex items-center space-x-2 p-2 rounded-md ${
                  isActive ? 'bg-blue-700 text-blue-300' : 'text-white hover:bg-gray-700'
                }`
              }
            >
              <span>📍</span>
              <span>Live Tracking</span>
            </NavLink>
          </li>
          <li>
            <NavLink
              to="/route-optimization"
              className={({ isActive }) =>
                `flex items-center space-x-2 p-2 rounded-md ${
                  isActive ? 'bg-blue-700 text-blue-300' : 'text-white hover:bg-gray-700'
                }`
              }
            >
              <span>🛤️</span>
              <span>Route Optimization</span>
            </NavLink>
          </li>
          <li>
            <NavLink
              to="/traffic-layer"
              className={({ isActive }) =>
                `flex items-center space-x-2 p-2 rounded-md ${
                  isActive ? 'bg-blue-700 text-blue-300' : 'text-white hover:bg-gray-700'
                }`
              }
            >
              <span>🚦</span>
              <span>Traffic Layer</span>
            </NavLink>
          </li>
          <li>
            <NavLink
              to="/notifications"
              className={({ isActive }) =>
                `flex items-center space-x-2 p-2 rounded-md ${
                  isActive ? 'bg-blue-700 text-blue-300' : 'text-white hover:bg-gray-700'
                }`
              }
            >
              <span>🔔</span>
              <span>Notifications</span>
            </NavLink>
          </li>
        </ul>
      </nav>
    </div>
  );
};
export default Sidebar;
